function e(e=90,t=65e3){let n=[],r=t,i=Date.now();for(let t=e;t>=0;t--){let e=new Date(i-t*864e5),a=.02+Math.random()*.04,o=(Math.random()-.48)*a,s=r;r=s*(1+o);let c=Math.max(s,r)*(1+Math.random()*.015),l=Math.min(s,r)*(1-Math.random()*.015),u=500+Math.random()*2e3;n.push({date:e.toISOString().slice(0,10),open:+s.toFixed(2),high:+c.toFixed(2),low:+l.toFixed(2),close:+r.toFixed(2),volume:+u.toFixed(0)})}return n}function t(e,t){return e.map((n,r)=>{if(r<t-1)return{...n,sma:null};let i=e.slice(r-t+1,r+1);return{...n,sma:+(i.reduce((e,t)=>e+t.close,0)/t).toFixed(2)}})}function n(e,t=14){return e.map((n,r)=>{if(r<t)return{...n,rsi:null};let i=e.slice(r-t,r),a=0,o=0;for(let e=1;e<i.length;e++){let t=i[e].close-i[e-1].close;t>0?a+=t:o-=t}let s=o===0?100:a/o;return{...n,rsi:+(100-100/(1+s)).toFixed(1)}})}function r(e,t=20,n=2){return e.map((r,i)=>{if(i<t-1)return{...r,bb_mid:null,bb_upper:null,bb_lower:null};let a=e.slice(i-t+1,i+1),o=a.reduce((e,t)=>e+t.close,0)/t,s=Math.sqrt(a.reduce((e,t)=>e+(t.close-o)**2,0)/t);return{...r,bb_mid:+o.toFixed(2),bb_upper:+(o+n*s).toFixed(2),bb_lower:+(o-n*s).toFixed(2)}})}var i=[{id:`grid`,name:`Grid Trading`,risk:`Medium`,returnRange:`12-60% annual`,bestMarket:`Range-bound`,aiValue:`Moderate-High`,description:`Places buy and sell orders at fixed intervals within a price range. AI dynamically adjusts grid range and spacing based on volatility.`,beginnerDesc:`Imagine buying a coin every time it drops $100, and selling every time it rises $100. That's grid trading — it profits from price bouncing up and down, even when the overall direction isn't clear.`,whenToUse:`When prices are moving sideways — not clearly going up or down. Grid bots love choppy markets.`,whenToAvoid:`When the market is in a strong trend (big moves up or down). Grid bots can get caught on the wrong side.`,marketFit:{trending:`poor`,ranging:`excellent`,volatile:`good`,calm:`good`},params:[{key:`gridRange`,label:`Grid Range (%)`,default:10,min:1,max:50},{key:`gridLevels`,label:`Grid Levels`,default:10,min:3,max:50},{key:`investmentPerLevel`,label:`$ per Level`,default:100,min:10,max:1e4}]},{id:`dca`,name:`Smart DCA`,risk:`Low-Medium`,returnRange:`8-30% annual`,bestMarket:`Volatile uptrend`,aiValue:`Moderate`,description:`Dollar-cost averaging with AI timing. Increases buys during dips, reduces during euphoria using RSI and sentiment signals.`,beginnerDesc:`Instead of investing all your money at once, you buy a little bit on a regular schedule — like $50 every week. The "smart" part means it buys more when prices are low and less when they're high.`,whenToUse:`When you want steady, low-stress investing. Perfect for beginners and for building a position over time.`,whenToAvoid:`When you need quick returns or the market is crashing hard with no signs of recovery.`,marketFit:{trending:`good`,ranging:`fair`,volatile:`excellent`,calm:`fair`},params:[{key:`baseAmount`,label:`Base Buy ($)`,default:50,min:10,max:5e3},{key:`interval`,label:`Interval (hrs)`,default:24,min:1,max:168},{key:`dipMultiplier`,label:`Dip Multiplier`,default:2,min:1,max:5}]},{id:`trend`,name:`Trend Following`,risk:`Medium-High`,returnRange:`15-40% annual`,bestMarket:`Strong trends`,aiValue:`Moderate`,description:`Identifies momentum using EMA crossovers, MACD, and breakouts. AI filters false breakouts using volume/order-flow classifiers.`,beginnerDesc:`This strategy tries to ride the wave. When a coin starts moving strongly in one direction, trend following jumps in and rides it — buying when prices are going up, and getting out before they fall.`,whenToUse:`When the market has clear momentum — big moves with strong volume. Think BTC breaking a new all-time high.`,whenToAvoid:`When the market is choppy and directionless. Trend followers get chopped up in sideways markets.`,marketFit:{trending:`excellent`,ranging:`poor`,volatile:`good`,calm:`fair`},params:[{key:`fastEMA`,label:`Fast EMA`,default:12,min:5,max:50},{key:`slowEMA`,label:`Slow EMA`,default:26,min:20,max:200},{key:`signalThreshold`,label:`Threshold`,default:.02,min:.005,max:.1}]},{id:`meanReversion`,name:`Mean Reversion`,risk:`Medium`,returnRange:`10-25% annual`,bestMarket:`Range-bound`,aiValue:`High`,description:`Trades statistical deviations using Bollinger Bands and z-scores. ML detects regime changes to pause during structural breaks.`,beginnerDesc:`What goes up must come down — and vice versa. Mean reversion bets that when a price moves too far from its average, it'll snap back. It buys dips and sells rallies.`,whenToUse:`In stable, range-bound markets where prices oscillate around a central value.`,whenToAvoid:`During strong trends or when a fundamental event breaks the old range (e.g., a major protocol hack).`,marketFit:{trending:`fair`,ranging:`excellent`,volatile:`good`,calm:`good`},params:[{key:`bbPeriod`,label:`BB Period`,default:20,min:10,max:50},{key:`bbStdDev`,label:`BB Std Dev`,default:2,min:1,max:3},{key:`zScoreThreshold`,label:`Z-Score`,default:2,min:1,max:3}]},{id:`sentiment`,name:`Sentiment Trading`,risk:`High`,returnRange:`20-60% annual`,bestMarket:`News-driven`,aiValue:`Essential`,description:`NLP models analyze social media, news, and Fear & Greed. LLMs classify sentiment and generate contrarian signals.`,beginnerDesc:`This one reads the room. It scans Twitter, news headlines, and market sentiment to figure out how people are feeling — then does the opposite when everyone is too scared or too greedy.`,whenToUse:`Around major events, news, or when sentiment is at extremes (very high fear or greed).`,whenToAvoid:`In quiet markets with no news flow. Sentiment signals are noisy when nothing is happening.`,marketFit:{trending:`good`,ranging:`fair`,volatile:`excellent`,calm:`poor`},params:[{key:`sentimentThreshold`,label:`Threshold`,default:.6,min:.1,max:.9},{key:`lookbackHours`,label:`Lookback (hrs)`,default:24,min:1,max:168},{key:`contrarianWeight`,label:`Contrarian Wt`,default:.3,min:0,max:1}]},{id:`arbitrage`,name:`Cross-Exchange Arb`,risk:`Medium-Low`,returnRange:`0.1-2% per trade`,bestMarket:`Fragmented liquidity`,aiValue:`High`,description:`Exploits price discrepancies across exchanges. AI predicts which gaps persist and optimizes routing across DEXs/bridges.`,beginnerDesc:`Buy BTC for $64,000 on one exchange, sell it for $64,200 on another. Arbitrage finds these tiny price differences and makes quick, low-risk trades to capture the gap.`,whenToUse:`When there's big volume but prices differ across exchanges — usually during high volatility or in fragmented markets.`,whenToAvoid:`When spreads are too thin to cover gas/transfer fees, or during network congestion.`,marketFit:{trending:`fair`,ranging:`good`,volatile:`excellent`,calm:`poor`},params:[{key:`minSpread`,label:`Min Spread (%)`,default:.3,min:.05,max:2},{key:`maxLatency`,label:`Max Latency (ms)`,default:500,min:50,max:5e3},{key:`feeBuffer`,label:`Fee Buffer (%)`,default:.1,min:.01,max:.5}]}],a={sharpe:{name:`Sharpe Ratio`,good:`> 1.5`,desc:`Risk-adjusted return above risk-free rate`},sortino:{name:`Sortino Ratio`,good:`> 2.0`,desc:`Downside risk-adjusted return`},maxDrawdown:{name:`Max Drawdown`,good:`< 15%`,desc:`Largest peak-to-trough decline`},winRate:{name:`Win Rate`,good:`> 55%`,desc:`Percentage of profitable trades`},profitFactor:{name:`Profit Factor`,good:`> 1.5`,desc:`Gross profit / gross loss`},calmar:{name:`Calmar Ratio`,good:`> 2.0`,desc:`Annual return / max drawdown`}};function o(e,t,n,r){let i=t/100*e,a=Math.abs(n-r);return a===0?0:+(i/a).toFixed(6)}function s(e,t,n){if(n===0)return 0;let r=t/n;return+Math.max(0,Math.min((e*r-(1-e))/r,.25)).toFixed(4)}function c(e,t=14){if(e.length<t+1)return 0;let n=0;for(let r=1;r<=t;r++){let t=Math.max(e[r].high-e[r].low,Math.abs(e[r].high-e[r-1].close),Math.abs(e[r].low-e[r-1].close));n+=t}return+(n/t).toFixed(2)}export{o as a,t as c,s as i,e as l,i as n,r as o,c as r,n as s,a as t};